563→// ---------------------------------------------------------------------------
564→// OAuth / JWT Token Helpers (for MCP endpoint tests)
565→// ---------------------------------------------------------------------------
566→
567→function base64url(buf: Buffer): string {
568→  return buf.toString("base64url");
569→}
570→
571→function generatePkce(): { verifier: string; challenge: string } {
572→  const verifier = base64url(randomBytes(32));
573→  const challenge = base64url(createHash("sha256").update(verifier).digest());
574→  return { verifier, challenge };
575→}
576→
577→const MCP_SCOPES = "graph:read graph:reason decision:write task:write observation:write question:write session:write offline_access";
578→
579→/**
580→ * Obtains a JWT Bearer token for a test user via the full OAuth 2.1 flow.
581→ * Required for MCP endpoints which validate JWT tokens (not session cookies).
582→ *
583→ * Flow: register OAuth client → skip consent → authorize with PKCE → exchange for JWT
584→ */
585→export async function getTestUserBearerToken(
586→  baseUrl: string,
587→  surreal: Surreal,
588→  user: TestUser,
589→  scopes?: string,
590→): Promise<TestUserWithToken> {
591→  // Trigger JWKS key generation
592→  await fetch(`${baseUrl}/api/auth/jwks`);
593→
594→  // Register a public OAuth client via DCR
595→  const dcrRes = await fetch(`${baseUrl}/api/auth/oauth2/register`, {
596→    method: "POST",
597→    headers: { "Content-Type": "application/json" },
598→    body: JSON.stringify({
599→      client_name: `test-client-${Date.now()}`,
600→      redirect_uris: ["http://127.0.0.1:9999/callback"],
601→      grant_types: ["authorization_code", "refresh_token"],
602→      response_types: ["code"],
603→      token_endpoint_auth_method: "none",
604→    }),
605→  });
606→
607→  if (!dcrRes.ok) {
608→    throw new Error(`DCR failed: ${dcrRes.status} ${await dcrRes.text()}`);
609→  }
610→
611→  const { client_id } = (await dcrRes.json()) as { client_id: string };
612→
613→  // Skip consent for test clients
614→  await surreal.query(
615→    `UPDATE oauthClient SET skipConsent = true WHERE clientId = $cid;`,
616→    { cid: client_id },
617→  );
618→
619→  // Get authorization code with PKCE
620→  const { verifier, challenge } = generatePkce();
621→  const authUrl = new URL(`${baseUrl}/api/auth/oauth2/authorize`);
622→  authUrl.searchParams.set("client_id", client_id);
623→  authUrl.searchParams.set("redirect_uri", "http://127.0.0.1:9999/callback");
624→  authUrl.searchParams.set("response_type", "code");
625→  authUrl.searchParams.set("scope", scopes ?? MCP_SCOPES);
626→  authUrl.searchParams.set("state", "test-state");
627→  authUrl.searchParams.set("code_challenge", challenge);
628→  authUrl.searchParams.set("code_challenge_method", "S256");
629→  // Pass resource so better-auth issues a JWT (not opaque token)
630→  authUrl.searchParams.set("resource", baseUrl);
631→
632→  const authRes = await fetch(authUrl.toString(), {
633→    headers: user.headers,
634→    redirect: "manual",
635→  });
636→
637→  if (authRes.status !== 302) {
638→    const body = await authRes.text();
639→    throw new Error(`OAuth authorize did not redirect: ${authRes.status} body=${body}`);
640→  }
641→
642→  const location = authRes.headers.get("location");
643→  if (!location) throw new Error("No location header in auth redirect");
644→  const redirectUrl = new URL(location, baseUrl);
645→  const code = redirectUrl.searchParams.get("code") ?? "";
646→  if (!code) {
647→    const error = redirectUrl.searchParams.get("error");
648→    throw new Error(`No code in redirect: ${location} (error=${error})`);
649→  }
650→
651→  // Exchange code for tokens
652→  const tokenRes = await fetch(`${baseUrl}/api/auth/oauth2/token`, {
653→    method: "POST",
654→    headers: { "Content-Type": "application/x-www-form-urlencoded" },
655→    body: new URLSearchParams({
656→      grant_type: "authorization_code",
657→      code,
658→      redirect_uri: "http://127.0.0.1:9999/callback",
659→      client_id,
660→      code_verifier: verifier,
661→      resource: baseUrl,
662→    }),
663→  });
664→
665→  if (!tokenRes.ok) {
666→    throw new Error(`Token exchange failed: ${tokenRes.status} ${await tokenRes.text()}`);
667→  }
668→
669→  const tokens = (await tokenRes.json()) as {
670→    access_token: string;
671→    refresh_token: string;
672→    expires_in: number;
673→  };
674→
675→  return {
676→    ...user,
677→    accessToken: tokens.access_token,
678→    bearerHeaders: {
679→      "Content-Type": "application/json",
680→      Authorization: `Bearer ${tokens.access_token}`,
681→    },
682→  };
683→}
