689→export async function fetchJson<T>(url: string, init?: RequestInit): Promise<T> {
690→  const response = await fetch(url, init);
691→  if (!response.ok) {
692→    const body = await response.text();
693→    throw new Error(`Request failed (${response.status}) ${url}: ${body}`);
694→  }
695→  return (await response.json()) as T;
696→}
697→
698→async function waitForHealth(
699→  url: string,
700→  process: ReturnType<typeof Bun.spawn>,
701→  timeoutMs: number,
702→): Promise<void> {
703→  const start = Date.now();
704→  while (Date.now() - start < timeoutMs) {
705→    if (typeof process.exitCode === "number") {
706→      const stderr = process.stderr
707→        ? await new Response(process.stderr).text()
708→        : "";
709→      throw new Error(
710→        `Server exited early with code ${process.exitCode}\n${stderr}`,
711→      );
712→    }
713→    try {
714→      const response = await fetch(`${url}/healthz`);
715→      if (response.ok) return;
716→    } catch {
717→      // Keep polling.
718→    }
719→    await Bun.sleep(200);
720→  }
721→  throw new Error(`Timed out waiting for server health at ${url}/healthz`);
722→}
723→
724→async function withTimeout<T>(
725→  callback: () => Promise<T>,
726→  timeoutMs: number,
727→  label: string,
728→): Promise<T> {
729→  return await Promise.race([
730→    callback(),
731→    new Promise<T>((_, reject) => {
732→      setTimeout(() => reject(new Error(`Timed out: ${label}`)), timeoutMs);
733→    }),
734→  ]);
735→}
