  1→/**
  2→ * Walking Skeleton: Assign Task to Agent, Monitor, Accept
  3→ *
  4→ * Traces: US-0.1, US-0.2, US-0.3, US-2.2
  5→ *
  6→ * This is the minimum viable E2E path through the coding agent orchestrator.
  7→ * A user assigns a task to an agent, monitors its status, and accepts the
  8→ * completed work. This is the FIRST test to enable -- all others start skipped.
  9→ *
 10→ * Driving ports: POST /api/orchestrator/:ws/assign
 11→ *                GET  /api/orchestrator/:ws/sessions/:id
 12→ *                POST /api/orchestrator/:ws/sessions/:id/accept
 13→ */
 14→import { describe, expect, it } from "bun:test";
 15→import {
 16→  setupOrchestratorSuite,
 17→  createTestUser,
 18→  createTestWorkspace,
 19→  createReadyTask,
 20→  assignTaskToAgent,
 21→  getSessionStatus,
 22→  acceptAgentWork,
 23→  simulateSessionStatus,
 24→  getTaskStatus,
 25→  getAgentSessionsForTask,
 26→} from "./orchestrator-test-kit";
 27→
 28→const getRuntime = setupOrchestratorSuite("walking_skeleton");
 29→
 30→describe("Walking Skeleton: User assigns task, monitors agent, accepts work", () => {
 31→  // -------------------------------------------------------------------------
 32→  // Walking Skeleton 1: Complete assign-monitor-accept journey
 33→  // US-0.1 + US-2.2
 34→  // -------------------------------------------------------------------------
 35→  it("user assigns a ready task to an agent, checks progress, and accepts the result", async () => {
 36→    const { baseUrl, surreal } = getRuntime();
 37→
 38→    // Given a user with a workspace containing a task ready for work
 39→    const user = await createTestUser(baseUrl, "skeleton");
 40→    const workspace = await createTestWorkspace(baseUrl, user);
 41→    const task = await createReadyTask(surreal, workspace.workspaceId, {
 42→      title: "Add login form validation",
 43→      description: "Validate email format and password strength on the login form",
 44→    });
 45→
 46→    // When the user assigns the task to a coding agent
 47→    const assignment = await assignTaskToAgent(
 48→      baseUrl,
 49→      user,
 50→      workspace.workspaceId,
 51→      task.taskId,
 52→    );
 53→
 54→    // Then an agent session is created with a stream for monitoring
 55→    expect(assignment.agentSessionId).toBeTruthy();
 56→    expect(assignment.streamUrl).toBeTruthy();
 57→
 58→    // And the task status changes to "in_progress"
 59→    const taskStatus = await getTaskStatus(surreal, task.taskId);
 60→    expect(taskStatus).toBe("in_progress");
 61→
 62→    // And the agent session is recorded in the workspace
 63→    const sessions = await getAgentSessionsForTask(surreal, task.taskId);
 64→    expect(sessions.length).toBe(1);
 65→    expect(sessions[0].agent).toBe("claude-agent-sdk");
 66→
 67→    // When the user checks the agent's progress
 68→    const status = await getSessionStatus(
 69→      baseUrl,
