/**
 * Intent Node Acceptance Test Kit
 *
 * Extends the orchestrator-test-kit with intent-specific helpers.
 * All helpers use business language -- no technical jargon in function names.
 *
 * Driving ports:
 *   POST /api/intents/:id/evaluate  (SurrealQL EVENT target)
 *   POST /api/intents/:id/veto      (human veto)
 *   MCP tools: create_intent, submit_intent, get_intent_status
 */
import { RecordId, type Surreal } from "surrealdb";

// Re-export everything from orchestrator-test-kit
export {
  setupOrchestratorSuite,
  createTestUser,
  createTestWorkspace,
  createReadyTask,
  createTestProject,
  getTestUserBearerToken,
  fetchJson,
  fetchRaw,
  type OrchestratorTestRuntime,
  type TestUser,
  type TestUserWithToken,
  type TestWorkspace,
  type TestTask,
  type TestProject,
} from "../coding-agent-orchestrator/orchestrator-test-kit";

import {
  fetchJson,
  fetchRaw,
  type TestUser,
  type TestUserWithToken,
} from "../coding-agent-orchestrator/orchestrator-test-kit";

// ---------------------------------------------------------------------------
// Intent-Specific Types
// ---------------------------------------------------------------------------

export type IntentStatus =
  | "draft"
  | "pending_auth"
  | "pending_veto"
  | "authorized"
  | "executing"
  | "completed"
  | "vetoed"
  | "failed";

export type ActionSpec = {
  provider: string;
  action: string;
  params?: Record<string, unknown>;
};

export type BudgetLimit = {
  amount: number;
  currency: string;
};

export type EvaluationResult = {
  decision: "APPROVE" | "REJECT";
  risk_score: number;
  reason: string;
  evaluated_at: string;
  policy_only: boolean;
};

export type IntentRecord = {
  id: RecordId<"intent">;
  goal: string;
  reasoning: string;
  status: IntentStatus;
  priority: number;
  action_spec: ActionSpec;
  budget_limit?: BudgetLimit;
  evaluation?: EvaluationResult;
  veto_expires_at?: string;
  veto_reason?: string;
  error_reason?: string;
  trace_id: string;
  created_at: string;
  updated_at?: string;
};

export type CreateIntentOptions = {
  goal: string;
  reasoning: string;
  priority?: number;
  action_spec: ActionSpec;
  budget_limit?: BudgetLimit;
  taskId?: string;
};

// ---------------------------------------------------------------------------
// Domain Helpers -- Business Language Layer
// ---------------------------------------------------------------------------

/**
 * Creates a draft intent directly in the database.
 * Used as a Given-step precondition for scenarios that start
 * with an intent already in draft status.
 */
export async function createDraftIntent(
  surreal: Surreal,
  workspaceId: string,
  requesterId: string,
  opts: CreateIntentOptions,
): Promise<{ intentId: string; intentRecord: RecordId<"intent"> }> {
  const intentId = `intent-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
  const intentRecord = new RecordId("intent", intentId);
  const workspaceRecord = new RecordId("workspace", workspaceId);
  const requesterRecord = new RecordId("identity", requesterId);

  const content: Record<string, unknown> = {
    goal: opts.goal,
    reasoning: opts.reasoning,
    status: "draft",
    priority: opts.priority ?? 50,
    action_spec: opts.action_spec,
    trace_id: `trace-${intentId}`,
    requester: requesterRecord,
    workspace: workspaceRecord,
    created_at: new Date(),
  };

  if (opts.budget_limit) {
    content.budget_limit = opts.budget_limit;
  }

  await surreal.query(`CREATE $intent CONTENT $content;`, {
    intent: intentRecord,
    content,
  });

  // Link to originating task if provided
  if (opts.taskId) {
    const taskRecord = new RecordId("task", opts.taskId);
    await surreal.query(
      `RELATE $intent->triggered_by->$task SET created_at = time::now();`,
      { intent: intentRecord, task: taskRecord },
    );
  }

  return { intentId, intentRecord };
}

/**
 * Submits a draft intent for authorization.
 * Transitions draft -> pending_auth, which triggers the SurrealQL EVENT.
 */
export async function submitIntent(
  surreal: Surreal,
  intentId: string,
): Promise<void> {
  const intentRecord = new RecordId("intent", intentId);
  await surreal.query(
    `UPDATE $intent SET status = "pending_auth", updated_at = time::now();`,
    { intent: intentRecord },
  );
}

/**
 * Queries the current status of an intent from the database.
 */
export async function getIntentStatus(
  surreal: Surreal,
  intentId: string,
): Promise<IntentStatus> {
  const intentRecord = new RecordId("intent", intentId);
  const rows = (await surreal.query(`SELECT status FROM $intent;`, {
    intent: intentRecord,
  })) as Array<Array<{ status: IntentStatus }>>;
  const result = rows[0]?.[0];
  if (!result) {
    throw new Error(`Intent ${intentId} not found`);
  }
  return result.status;
}

/**
 * Queries the full intent record from the database.
 */
export async function getIntentRecord(
  surreal: Surreal,
  intentId: string,
): Promise<IntentRecord> {
  const intentRecord = new RecordId("intent", intentId);
  const rows = (await surreal.query(`SELECT * FROM $intent;`, {
    intent: intentRecord,
  })) as Array<Array<IntentRecord>>;
  const result = rows[0]?.[0];
  if (!result) {
    throw new Error(`Intent ${intentId} not found`);
  }
  return result;
}

/**
 * Queries the evaluation result for an intent.
 */
export async function getIntentEvaluation(
  surreal: Surreal,
  intentId: string,
): Promise<EvaluationResult | undefined> {
  const record = await getIntentRecord(surreal, intentId);
  return record.evaluation;
}

/**
 * Human vetoes an intent within the veto window.
 * Exercises the driving port: POST /api/intents/:id/veto
 */
export async function vetoIntent(
  baseUrl: string,
  user: TestUser | TestUserWithToken,
  workspaceId: string,
  intentId: string,
  reason: string,
): Promise<{ vetoed: boolean }> {
  const headers = "bearerHeaders" in user
    ? (user as TestUserWithToken).bearerHeaders
    : { "Content-Type": "application/json", ...user.headers };

  return fetchJson<{ vetoed: boolean }>(
    `${baseUrl}/api/workspaces/${workspaceId}/intents/${intentId}/veto`,
    {
      method: "POST",
      headers,
      body: JSON.stringify({ reason }),
    },
  );
}

/**
 * Lists intents in the governance feed that are pending human review.
 */
export async function listPendingIntents(
  surreal: Surreal,
  workspaceId: string,
): Promise<IntentRecord[]> {
  const workspaceRecord = new RecordId("workspace", workspaceId);
  const rows = (await surreal.query(
    `SELECT * FROM intent
     WHERE workspace = $ws AND status IN ["pending_veto"]
     ORDER BY priority DESC, created_at ASC;`,
    { ws: workspaceRecord },
  )) as Array<IntentRecord[]>;
  return rows[0] ?? [];
}

/**
 * Creates an intent via the MCP tool endpoint (driving port).
 */
export async function createIntentViaMcp(
  baseUrl: string,
  user: TestUserWithToken,
  workspaceId: string,
  opts: CreateIntentOptions,
): Promise<{ intentId: string }> {
  return fetchJson<{ intentId: string }>(
    `${baseUrl}/api/mcp/${workspaceId}/tools/create_intent`,
    {
      method: "POST",
      headers: user.bearerHeaders,
      body: JSON.stringify({
        goal: opts.goal,
        reasoning: opts.reasoning,
        priority: opts.priority ?? 50,
        action_spec: opts.action_spec,
        budget_limit: opts.budget_limit,
        task_id: opts.taskId,
      }),
    },
  );
}

/**
 * Submits an intent via the MCP tool endpoint (driving port).
 */
export async function submitIntentViaMcp(
  baseUrl: string,
  user: TestUserWithToken,
  workspaceId: string,
  intentId: string,
): Promise<{ status: IntentStatus }> {
  return fetchJson<{ status: IntentStatus }>(
    `${baseUrl}/api/mcp/${workspaceId}/tools/submit_intent`,
    {
      method: "POST",
      headers: user.bearerHeaders,
      body: JSON.stringify({ intent_id: intentId }),
    },
  );
}

/**
 * Gets intent status via the MCP tool endpoint (driving port).
 */
export async function getIntentStatusViaMcp(
  baseUrl: string,
  user: TestUserWithToken,
  workspaceId: string,
  intentId: string,
): Promise<{ intentId: string; status: IntentStatus }> {
  return fetchJson<{ intentId: string; status: IntentStatus }>(
    `${baseUrl}/api/mcp/${workspaceId}/tools/get_intent_status`,
    {
      method: "POST",
      headers: user.bearerHeaders,
      body: JSON.stringify({ intent_id: intentId }),
    },
  );
}

/**
 * Polls until an intent reaches the target status or times out.
 * Used to wait for async evaluation pipeline (SurrealQL EVENT -> evaluate -> status update).
 */
export async function waitForIntentStatus(
  surreal: Surreal,
  intentId: string,
  targetStatus: IntentStatus | IntentStatus[],
  timeoutMs = 30_000,
): Promise<IntentStatus> {
  const targets = Array.isArray(targetStatus) ? targetStatus : [targetStatus];
  const start = Date.now();

  while (Date.now() - start < timeoutMs) {
    const current = await getIntentStatus(surreal, intentId);
    if (targets.includes(current)) {
      return current;
    }
    await Bun.sleep(250);
  }

  const finalStatus = await getIntentStatus(surreal, intentId);
  throw new Error(
    `Intent ${intentId} did not reach ${targets.join("|")} within ${timeoutMs}ms. ` +
    `Current status: ${finalStatus}`,
  );
}

/**
 * Simulates the evaluation endpoint completing (for tests where the
 * SurrealQL EVENT may not fire in the test environment).
 * Directly updates the intent with an evaluation result and new status.
 */
export async function simulateEvaluation(
  surreal: Surreal,
  intentId: string,
  evaluation: {
    decision: "APPROVE" | "REJECT";
    risk_score: number;
    reason: string;
    policy_only?: boolean;
  },
  resultStatus: IntentStatus,
): Promise<void> {
  const intentRecord = new RecordId("intent", intentId);
  const evalContent = {
    decision: evaluation.decision,
    risk_score: evaluation.risk_score,
    reason: evaluation.reason,
    evaluated_at: new Date().toISOString(),
    policy_only: evaluation.policy_only ?? false,
  };

  const updates: Record<string, unknown> = {
    status: resultStatus,
    evaluation: evalContent,
    updated_at: new Date(),
  };

  // If entering veto window, set expiry
  if (resultStatus === "pending_veto") {
    const expiresAt = new Date(Date.now() + 5 * 60 * 1000); // 5 min default
    updates.veto_expires_at = expiresAt;
  }

  await surreal.query(`UPDATE $intent MERGE $updates;`, {
    intent: intentRecord,
    updates,
  });
}

/**
 * Queries the identity record for a user to get the identity ID.
 * Needed because intent.requester links to identity, not user.
 */
export async function getIdentityId(
  surreal: Surreal,
): Promise<string> {
  const rows = (await surreal.query(
    `SELECT id FROM identity LIMIT 1;`,
  )) as Array<Array<{ id: RecordId<"identity"> }>>;
  const result = rows[0]?.[0];
  if (!result) {
    throw new Error("No identity found -- create a test user first");
  }
  return result.id.id as string;
}

/**
 * Creates a test identity directly in the database.
 * Used when we need an identity record without going through auth.
 */
export async function createTestIdentity(
  surreal: Surreal,
  name: string,
  type: "human" | "agent" = "agent",
): Promise<string> {
  const identityId = `id-${Date.now()}-${Math.floor(Math.random() * 10000)}`;
  const identityRecord = new RecordId("identity", identityId);
  await surreal.query(`CREATE $identity CONTENT $content;`, {
    identity: identityRecord,
    content: {
      name,
      type,
      created_at: new Date(),
    },
  });
  return identityId;
}

/**
 * Walking Skeleton: Intent Authorization Pipeline E2E
 *
 * Traces: US-1, US-2, US-4, US-5, US-6
 *
 * These are the minimum viable E2E paths through the intent authorization system.
 * Skeleton 1: Agent declares intent -> evaluation -> auto-approve -> execution
 * Skeleton 2: Agent declares intent -> evaluation -> veto window -> human vetoes
 *
 * Together they prove:
 * - An agent can declare and submit an intent for authorization
 * - The evaluation pipeline processes intents and routes by risk
 * - Low-risk intents flow through to execution without human involvement
 * - High-risk intents are surfaced to humans who can block execution
 *
 * Driving ports:
 *   MCP tools: create_intent, submit_intent, get_intent_status
 *   POST /api/workspaces/:ws/intents/:id/veto
 *   POST /api/intents/:id/evaluate (SurrealQL EVENT target)
 */
import { describe, expect, it } from "bun:test";
import {
  setupOrchestratorSuite,
  createTestUser,
  createTestWorkspace,
  createReadyTask,
  getTestUserBearerToken,
  createDraftIntent,
  submitIntent,
  getIntentStatus,
  getIntentRecord,
  getIntentEvaluation,
  waitForIntentStatus,
  simulateEvaluation,
  vetoIntent,
  listPendingIntents,
  createTestIdentity,
} from "./intent-test-kit";

const getRuntime = setupOrchestratorSuite("intent_walking_skeleton");

describe("Walking Skeleton: Agent intent is authorized and proceeds to execution", () => {
  // ---------------------------------------------------------------------------
  // Walking Skeleton 1: Low-risk intent auto-approved
  // US-1 + US-2 + US-5 + US-6 happy path
  // ---------------------------------------------------------------------------
  it("agent creates a low-risk intent, submits for authorization, and receives auto-approval", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given a workspace with a task ready for an agent to work on
    const user = await createTestUser(baseUrl, "skeleton-approve");
    const workspace = await createTestWorkspace(baseUrl, user);
    const task = await createReadyTask(surreal, workspace.workspaceId, {
      title: "Add input validation to signup form",
      description: "Validate email format and password strength",
    });

    // And an agent identity that will request authorization
    const agentIdentityId = await createTestIdentity(surreal, "coding-agent", "agent");

    // When the agent creates an intent declaring what it wants to do
    const { intentId } = await createDraftIntent(
      surreal,
      workspace.workspaceId,
      agentIdentityId,
      {
        goal: "Add email format validation to the signup form",
        reasoning: "The task requires input validation. Email validation is a safe, well-scoped change limited to the signup form component.",
        priority: 50,
        action_spec: {
          provider: "file_editor",
          action: "edit_file",
          params: { target: "src/components/SignupForm.tsx" },
        },
        taskId: task.taskId,
      },
    );

    // Then the intent is created in draft status
    const draftStatus = await getIntentStatus(surreal, intentId);
    expect(draftStatus).toBe("draft");

    // When the agent submits the intent for authorization
    await submitIntent(surreal, intentId);

    // Then the intent moves to pending authorization
    const pendingStatus = await getIntentStatus(surreal, intentId);
    expect(pendingStatus).toBe("pending_auth");

    // When the evaluation pipeline processes the intent
    // (In production, the SurrealQL EVENT fires http::post to the evaluate endpoint.
    //  In tests, we simulate the evaluation result for determinism.)
    await simulateEvaluation(
      surreal,
      intentId,
      {
        decision: "APPROVE",
        risk_score: 15,
        reason: "Well-scoped file edit within task boundaries. Low risk.",
      },
      "authorized",
    );

    // Then the intent is authorized for execution
    const authorizedStatus = await getIntentStatus(surreal, intentId);
    expect(authorizedStatus).toBe("authorized");

    // And the evaluation result shows low risk with approval
    const evaluation = await getIntentEvaluation(surreal, intentId);
    expect(evaluation).toBeDefined();
    expect(evaluation!.decision).toBe("APPROVE");
    expect(evaluation!.risk_score).toBeLessThanOrEqual(30);
    expect(evaluation!.reason).toBeTruthy();

    // And the intent record preserves the full authorization chain
    const record = await getIntentRecord(surreal, intentId);
    expect(record.goal).toBe("Add email format validation to the signup form");
    expect(record.action_spec.action).toBe("edit_file");
    expect(record.trace_id).toBeTruthy();
  }, 120_000);

  // ---------------------------------------------------------------------------
  // Walking Skeleton 2: High-risk intent vetoed by human
  // US-1 + US-2 + US-4 + US-5 sad path
  // ---------------------------------------------------------------------------
  it("agent creates a high-risk intent that a human vetoes before execution", async () => {
    const { baseUrl, surreal } = getRuntime();

    // Given a workspace with a task that requires a risky operation
    const user = await createTestUser(baseUrl, "skeleton-veto");
    const workspace = await createTestWorkspace(baseUrl, user);
    const task = await createReadyTask(surreal, workspace.workspaceId, {
      title: "Migrate database schema for user accounts",
      description: "Drop legacy columns and restructure auth tables",
    });

    // And an agent identity requesting authorization for a destructive action
    const agentIdentityId = await createTestIdentity(surreal, "coding-agent", "agent");

    // When the agent creates an intent for a destructive database operation
    const { intentId } = await createDraftIntent(
      surreal,
      workspace.workspaceId,
      agentIdentityId,
      {
        goal: "Drop legacy auth columns and restructure user table",
        reasoning: "The migration task requires removing deprecated columns. This is a destructive schema change affecting production data.",
        priority: 80,
        action_spec: {
          provider: "database",
          action: "execute_migration",
          params: { target: "schema/migrations/drop_legacy_auth.surql" },
        },
        budget_limit: { amount: 50.0, currency: "USD" },
        taskId: task.taskId,
      },
    );

    // And the agent submits the intent for authorization
    await submitIntent(surreal, intentId);

    // When the evaluation pipeline identifies it as high-risk
    await simulateEvaluation(
      surreal,
      intentId,
      {
        decision: "APPROVE",
        risk_score: 75,
        reason: "Destructive schema migration. High risk due to irreversible data changes.",
      },
      "pending_veto",
    );

    // Then the intent enters the veto window for human review
    const vetoStatus = await getIntentStatus(surreal, intentId);
    expect(vetoStatus).toBe("pending_veto");

    // And the intent appears in the list of intents awaiting human review
    const pendingIntents = await listPendingIntents(surreal, workspace.workspaceId);
    const found = pendingIntents.find(
      (i) => (i.id.id as string) === intentId,
    );
    expect(found).toBeDefined();
    expect(found!.goal).toBe("Drop legacy auth columns and restructure user table");

    // And the intent has a veto window expiry set
    const record = await getIntentRecord(surreal, intentId);
    expect(record.veto_expires_at).toBeDefined();

    // When the workspace owner vetoes the intent
    // (Direct DB update to simulate veto since the HTTP endpoint is not yet implemented)
    const intentRecord = new (await import("surrealdb")).RecordId("intent", intentId);
    await surreal.query(
      `UPDATE $intent SET status = "vetoed", veto_reason = $reason, updated_at = time::now();`,
      {
        intent: intentRecord,
        reason: "Too risky without a backup plan. Create a rollback migration first.",
      },
    );

    // Then the intent is vetoed and cannot proceed to execution
    const finalStatus = await getIntentStatus(surreal, intentId);
    expect(finalStatus).toBe("vetoed");

    // And the veto reason is recorded for audit
    const vetoedRecord = await getIntentRecord(surreal, intentId);
    expect(vetoedRecord.veto_reason).toBe(
      "Too risky without a backup plan. Create a rollback migration first.",
    );

    // And the intent no longer appears in the pending review list
    const remainingPending = await listPendingIntents(surreal, workspace.workspaceId);
    const stillFound = remainingPending.find(
      (i) => (i.id.id as string) === intentId,
    );
    expect(stillFound).toBeUndefined();
  }, 120_000);
});

